/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements the NotificationAdapter interface with:
 * - Template rendering based on notification type
 * - Recipient validation
 * - Priority-based handling
 * - Configurable send behavior (for testing vs production use)
 *
 * In dev/test mode, emails are stored in memory. A production implementation
 * would integrate with an SMTP service or email API (SendGrid, SES, etc.).
 */

import type { NotificationPayload, NotificationType } from '../models/notification.js';
import type { NotificationAdapter, NotificationDeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * A record of an email that was "sent" (logged in dev/test).
 */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  htmlBody: string;
  priority: string;
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * Email template structure returned by the template renderer.
 */
export interface EmailTemplate {
  subject: string;
  textBody: string;
  htmlBody: string;
}

/**
 * Configuration for the EmailAdapter.
 */
export interface EmailAdapterConfig {
  fromAddress: string;
  fromName: string;
  replyToAddress?: string;
}

const DEFAULT_CONFIG: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  fromName: 'TaskFlow Pro',
};

/**
 * Simple email address validation.
 */
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

/**
 * Escapes HTML special characters to prevent XSS in email bodies.
 */
function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];
  private config: EmailAdapterConfig;

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Send a notification via email.
   *
   * Validates the recipient, renders the template, and stores the email.
   * Returns a delivery result indicating success or failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationDeliveryResult> {
    // Validate recipient
    if (!payload.recipient || !isValidEmail(payload.recipient)) {
      this.logger.error(`Invalid email recipient: ${payload.recipient}`);
      return {
        success: false,
        channel: 'email',
        error: `Invalid email address: ${payload.recipient}`,
      };
    }

    try {
      // Render template based on notification type
      const template = this.renderTemplate(payload);

      this.logger.info(
        `Sending ${payload.priority}-priority email to ${payload.recipient}: ${template.subject}`,
      );

      const email: SentEmail = {
        to: payload.recipient,
        subject: template.subject,
        body: template.textBody,
        htmlBody: template.htmlBody,
        priority: payload.priority,
        sentAt: new Date(),
        metadata: payload.metadata,
      };

      this.sentEmails.push(email);

      return {
        success: true,
        channel: 'email',
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return {
        success: false,
        channel: 'email',
        error: message,
      };
    }
  }

  /**
   * Render an email template based on the notification type.
   * Returns both plain-text and HTML versions of the email.
   */
  renderTemplate(payload: NotificationPayload): EmailTemplate {
    const renderer = TEMPLATE_RENDERERS[payload.type];
    if (!renderer) {
      // Fallback: use the payload subject/body directly
      return {
        subject: payload.subject,
        textBody: payload.body,
        htmlBody: this.wrapInHtmlLayout(
          escapeHtml(payload.subject),
          `<p>${escapeHtml(payload.body)}</p>`,
        ),
      };
    }
    return renderer(payload, this.config);
  }

  /**
   * Wrap content in a standard HTML email layout.
   */
  private wrapInHtmlLayout(title: string, bodyContent: string): string {
    return [
      '<!DOCTYPE html>',
      '<html>',
      '<head><meta charset="utf-8"></head>',
      '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h2>${title}</h2>`,
      bodyContent,
      `<hr><p style="color: #888; font-size: 12px;">Sent by ${escapeHtml(this.config.fromName)}</p>`,
      '</body>',
      '</html>',
    ].join('\n');
  }

  /**
   * Resolve a recipient identifier to a display-friendly format.
   * Useful for logging and template rendering.
   */
  resolveRecipientDisplay(email: string): string {
    const localPart = email.split('@')[0] ?? email;
    // Capitalize first letter of local part as a display name fallback
    return localPart.charAt(0).toUpperCase() + localPart.slice(1);
  }

  /**
   * Get the adapter configuration (read-only copy).
   */
  getConfig(): Readonly<EmailAdapterConfig> {
    return { ...this.config };
  }

  /**
   * Get all sent emails (useful for testing).
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Template renderers keyed by notification type.
 * Each renderer produces an EmailTemplate from a NotificationPayload.
 */
const TEMPLATE_RENDERERS: Record<
  NotificationType,
  (payload: NotificationPayload, config: EmailAdapterConfig) => EmailTemplate
> = {
  order_confirmation(payload, config) {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    const escapedBody = escapeHtml(payload.body);
    const htmlBody = [
      '<!DOCTYPE html>',
      '<html>',
      '<head><meta charset="utf-8"></head>',
      '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h2>Order Confirmation</h2>',
      `<p>Thank you for your order <strong>${escapeHtml(orderId)}</strong>!</p>`,
      `<p>${escapedBody}</p>`,
      `<hr><p style="color: #888; font-size: 12px;">Sent by ${escapeHtml(config.fromName)}</p>`,
      '</body>',
      '</html>',
    ].join('\n');

    return {
      subject: payload.subject,
      textBody: payload.body,
      htmlBody,
    };
  },

  order_status_update(payload, config) {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    const previousStatus = (payload.metadata?.previousStatus as string) ?? '';
    const newStatus = (payload.metadata?.newStatus as string) ?? '';
    const escapedBody = escapeHtml(payload.body);
    const htmlBody = [
      '<!DOCTYPE html>',
      '<html>',
      '<head><meta charset="utf-8"></head>',
      '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h2>Order Status Update</h2>',
      `<p>Your order <strong>${escapeHtml(orderId)}</strong> has been updated.</p>`,
      `<p>Status: <del>${escapeHtml(previousStatus)}</del> &rarr; <strong>${escapeHtml(newStatus)}</strong></p>`,
      `<p>${escapedBody}</p>`,
      `<hr><p style="color: #888; font-size: 12px;">Sent by ${escapeHtml(config.fromName)}</p>`,
      '</body>',
      '</html>',
    ].join('\n');

    return {
      subject: payload.subject,
      textBody: payload.body,
      htmlBody,
    };
  },

  welcome(payload, config) {
    const escapedBody = escapeHtml(payload.body);
    const htmlBody = [
      '<!DOCTYPE html>',
      '<html>',
      '<head><meta charset="utf-8"></head>',
      '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h2>Welcome to ${escapeHtml(config.appName ?? config.fromName)}!</h2>`,
      `<p>${escapedBody}</p>`,
      `<hr><p style="color: #888; font-size: 12px;">Sent by ${escapeHtml(config.fromName)}</p>`,
      '</body>',
      '</html>',
    ].join('\n');

    return {
      subject: payload.subject,
      textBody: payload.body,
      htmlBody,
    };
  },

  account_updated(payload, config) {
    const escapedBody = escapeHtml(payload.body);
    const htmlBody = [
      '<!DOCTYPE html>',
      '<html>',
      '<head><meta charset="utf-8"></head>',
      '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h2>Account Updated</h2>',
      `<p>${escapedBody}</p>`,
      `<hr><p style="color: #888; font-size: 12px;">Sent by ${escapeHtml(config.fromName)}</p>`,
      '</body>',
      '</html>',
    ].join('\n');

    return {
      subject: payload.subject,
      textBody: payload.body,
      htmlBody,
    };
  },
};

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body content',
    type: 'order_confirmation',
    channel: 'email',
    priority: 'normal',
    metadata: { orderId: 'order-1' },
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('send', () => {
    it('should successfully send a valid email', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.error).toBeUndefined();
    });

    it('should store sent email with correct fields', async () => {
      await adapter.send(makePayload());

      const emails = adapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
      expect(emails[0]?.body).toBe('Test body content');
      expect(emails[0]?.htmlBody).toBeDefined();
      expect(emails[0]?.priority).toBe('normal');
      expect(emails[0]?.sentAt).toBeInstanceOf(Date);
      expect(emails[0]?.metadata).toEqual({ orderId: 'order-1' });
    });

    it('should fail for invalid email address', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.channel).toBe('email');
      expect(result.error).toContain('Invalid email address');
    });

    it('should fail for empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should not store email on validation failure', async () => {
      await adapter.send(makePayload({ recipient: 'bad' }));

      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should handle multiple sends', async () => {
      await adapter.send(makePayload({ recipient: 'alice@example.com' }));
      await adapter.send(makePayload({ recipient: 'bob@example.com' }));

      expect(adapter.getSentEmails()).toHaveLength(2);
    });

    it('should include priority in sent email', async () => {
      await adapter.send(makePayload({ priority: 'high' }));

      expect(adapter.getSentEmails()[0]?.priority).toBe('high');
    });
  });

  describe('template rendering', () => {
    it('should render order_confirmation template with order ID', () => {
      const template = adapter.renderTemplate(
        makePayload({ type: 'order_confirmation', metadata: { orderId: 'order-42' } }),
      );

      expect(template.subject).toBe('Test Subject');
      expect(template.textBody).toBe('Test body content');
      expect(template.htmlBody).toContain('Order Confirmation');
      expect(template.htmlBody).toContain('order-42');
    });

    it('should render order_status_update template with status info', () => {
      const template = adapter.renderTemplate(
        makePayload({
          type: 'order_status_update',
          metadata: { orderId: 'order-5', previousStatus: 'pending', newStatus: 'shipped' },
        }),
      );

      expect(template.htmlBody).toContain('Order Status Update');
      expect(template.htmlBody).toContain('pending');
      expect(template.htmlBody).toContain('shipped');
      expect(template.htmlBody).toContain('order-5');
    });

    it('should render welcome template', () => {
      const template = adapter.renderTemplate(
        makePayload({ type: 'welcome', body: 'Welcome aboard!' }),
      );

      expect(template.htmlBody).toContain('Welcome');
      expect(template.textBody).toBe('Welcome aboard!');
    });

    it('should render account_updated template', () => {
      const template = adapter.renderTemplate(
        makePayload({ type: 'account_updated', body: 'Your profile was changed.' }),
      );

      expect(template.htmlBody).toContain('Account Updated');
      expect(template.textBody).toBe('Your profile was changed.');
    });

    it('should escape HTML in template output', () => {
      const template = adapter.renderTemplate(
        makePayload({ body: '<script>alert("xss")</script>' }),
      );

      expect(template.htmlBody).not.toContain('<script>');
      expect(template.htmlBody).toContain('&lt;script&gt;');
    });

    it('should include sender info in HTML footer', () => {
      const template = adapter.renderTemplate(makePayload());

      expect(template.htmlBody).toContain('TaskFlow Pro');
    });
  });

  describe('recipient resolution', () => {
    it('should resolve email to capitalized local part', () => {
      expect(adapter.resolveRecipientDisplay('alice@example.com')).toBe('Alice');
    });

    it('should handle dotted local parts', () => {
      expect(adapter.resolveRecipientDisplay('john.doe@example.com')).toBe('John.doe');
    });
  });

  describe('configuration', () => {
    it('should use default config when none provided', () => {
      const config = adapter.getConfig();

      expect(config.fromAddress).toBe('noreply@taskflowpro.com');
      expect(config.fromName).toBe('TaskFlow Pro');
    });

    it('should accept custom config', () => {
      const custom = new EmailAdapter({
        fromAddress: 'support@myapp.com',
        fromName: 'My App',
      });

      const config = custom.getConfig();
      expect(config.fromAddress).toBe('support@myapp.com');
      expect(config.fromName).toBe('My App');
    });

    it('should use custom from name in HTML templates', () => {
      const custom = new EmailAdapter({ fromName: 'Custom Sender' });
      const template = custom.renderTemplate(makePayload());

      expect(template.htmlBody).toContain('Custom Sender');
    });
  });

  describe('email management', () => {
    it('should return defensive copy of sent emails', async () => {
      await adapter.send(makePayload());

      const emails1 = adapter.getSentEmails();
      const emails2 = adapter.getSentEmails();
      expect(emails1).not.toBe(emails2);
      expect(emails1).toEqual(emails2);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();

      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});

